import fs from 'fs';

import xlsx from 'xlsx';

import { objectsToCSV, parseCSVBuffer } from '@Libs/csvParser';

import { FileInterface } from '@Services/types/FileInterface';

export type TabularFormat = 'csv' | 'xlsx';

export function readFileBuffer(file: FileInterface): Buffer {
  if (file?.buffer?.length) {
    return file.buffer;
  }
  if (file?.path) {
    return fs.readFileSync(file.path);
  }
  return Buffer.from('');
}

export function parseTabularBuffer<T extends Record<string, any>>(buffer: Buffer, format: TabularFormat): T[] {
  if (format === 'xlsx') {
    const workbook = xlsx.read(buffer, { type: 'buffer' });
    const sheet = workbook.Sheets[workbook.SheetNames[0]];
    return xlsx.utils.sheet_to_json<T>(sheet, { defval: '' });
  }
  return parseCSVBuffer<T>(buffer);
}

export function exportTabular<T extends Record<string, any>>(rows: T[], format: TabularFormat): Buffer {
  if (format === 'xlsx') {
    const sheet = xlsx.utils.json_to_sheet(rows);
    const workbook = xlsx.utils.book_new();
    xlsx.utils.book_append_sheet(workbook, sheet, 'data');
    return xlsx.write(workbook, { type: 'buffer', bookType: 'xlsx' }) as Buffer;
  }
  const csv = objectsToCSV(rows);
  return Buffer.from(csv, 'utf-8');
}

export function normalizeFormat(format?: string): TabularFormat {
  return format === 'xlsx' ? 'xlsx' : 'csv';
}

